var testOpenAPISpec = []byte("openapi: 3.0.0\ninfo:\n  title: SocialPredict Test API\n")

func testSwaggerUIFS() fstest.MapFS {
	return fstest.MapFS{
		"swagger-ui/index.html": &fstest.MapFile{
			Data: []byte("<html>swagger</html>"),
